109	impl PartialEq for ZBuf {
110	    fn eq(&self, other: &Self) -> bool {
111	        let mut self_slices = self.slices();
112	        let mut other_slices = other.slices();
113	        let mut current_self = self_slices.next();
114	        let mut current_other = other_slices.next();
115	        loop {
116	            match (current_self, current_other) {
117	                (None, None) => return true,
118	                (None, _) | (_, None) => return false,
119	                (Some(l), Some(r)) => {
120	                    let cmp_len = l.len().min(r.len());
121	                    // SAFETY: cmp_len is the minimum length between l and r slices.
122	                    let lhs = crate::unsafe_slice!(l, ..cmp_len);
123	                    let rhs = crate::unsafe_slice!(r, ..cmp_len);
124	                    if lhs != rhs {
125	                        return false;
126	                    }
127	                    if cmp_len == l.len() {
128	                        current_self = self_slices.next();
129	                    } else {
130	                        // SAFETY: cmp_len is the minimum length between l and r slices.
131	                        let lhs = crate::unsafe_slice!(l, cmp_len..);
132	                        current_self = Some(lhs);
133	                    }
134	                    if cmp_len == r.len() {
135	                        current_other = other_slices.next();
136	                    } else {
137	                        // SAFETY: cmp_len is the minimum length between l and r slices.
138	                        let rhs = crate::unsafe_slice!(r, cmp_len..);
139	                        current_other = Some(rhs);
140	                    }
141	                }
142	            }
143	        }
144	    }
145	}
