183	#[derive(Debug, Clone)]
184	pub struct ZBufReader<'a> {
185	    inner: &'a ZBuf,
186	    cursor: ZBufPos,
187	}
188	
189	impl<'a> HasReader for &'a ZBuf {
190	    type Reader = ZBufReader<'a>;
191	
192	    fn reader(self) -> Self::Reader {
193	        ZBufReader {
194	            inner: self,
195	            cursor: ZBufPos { slice: 0, byte: 0 },
196	        }
197	    }
198	}
199	
200	impl Reader for ZBufReader<'_> {
201	    fn read(&mut self, mut into: &mut [u8]) -> Result<NonZeroUsize, DidntRead> {
202	        let mut read = 0;
203	        while let Some(slice) = self.inner.slices.get(self.cursor.slice) {
204	            // Subslice from the current read slice
205	            // SAFETY: validity of self.cursor.byte is ensured by the read logic.
206	            let from = crate::unsafe_slice!(slice.as_slice(), self.cursor.byte..);
207	            // Take the minimum length among read and write slices
208	            let len = from.len().min(into.len());
209	            // Copy the slice content
210	            // SAFETY: len is the minimum length between from and into slices.
211	            let lhs = crate::unsafe_slice_mut!(into, ..len);
212	            let rhs = crate::unsafe_slice!(from, ..len);
213	            lhs.copy_from_slice(rhs);
214	            // Advance the write slice
215	            // SAFETY: len is the minimum length between from and into slices.
216	            into = crate::unsafe_slice_mut!(into, len..);
217	            // Update the counter
218	            read += len;
219	            // Move the byte cursor
220	            self.cursor.byte += len;
221	            // We consumed all the current read slice, move to the next slice
222	            if self.cursor.byte == slice.len() {
223	                self.cursor.slice += 1;
224	                self.cursor.byte = 0;
225	            }
226	            // We have read everything we had to read
227	            if into.is_empty() {
228	                break;
229	            }
230	        }
231	        NonZeroUsize::new(read).ok_or(DidntRead)
232	    }
233	
234	    fn read_exact(&mut self, into: &mut [u8]) -> Result<(), DidntRead> {
235	        let len = Reader::read(self, into)?;
236	        if len.get() == into.len() {
237	            Ok(())
238	        } else {
239	            Err(DidntRead)
240	        }
241	    }
242	
243	    fn remaining(&self) -> usize {
244	        // SAFETY: self.cursor.slice validity is ensured by the reader
245	        let s = crate::unsafe_slice!(self.inner.slices.as_ref(), self.cursor.slice..);
246	        s.iter().fold(0, |acc, it| acc + it.len()) - self.cursor.byte
247	    }
248	
249	    fn read_zslices<F: FnMut(ZSlice)>(&mut self, len: usize, mut f: F) -> Result<(), DidntRead> {
250	        if self.remaining() < len {
251	            return Err(DidntRead);
252	        }
253	
254	        let iter = ZBufSliceIterator {
255	            reader: self,
256	            remaining: len,
257	        };
258	        for slice in iter {
259	            f(slice);
260	        }
261	
262	        Ok(())
263	    }
264	
265	    fn read_zslice(&mut self, len: usize) -> Result<ZSlice, DidntRead> {
266	        if self.remaining() < len {
267	            return Err(DidntRead);
268	        }
269	        let slice = self.inner.slices.get(self.cursor.slice).ok_or(DidntRead)?;
270	        match (slice.len() - self.cursor.byte).cmp(&len) {
271	            cmp::Ordering::Less => {
272	                let mut buffer = crate::vec::uninit(len);
273	                Reader::read_exact(self, &mut buffer)?;
274	                Ok(buffer.into())
275	            }
276	            cmp::Ordering::Equal => {
277	                let s = slice.subslice(self.cursor.byte..).ok_or(DidntRead)?;
278	                self.cursor.slice += 1;
279	                self.cursor.byte = 0;
280	                Ok(s)
281	            }
282	            cmp::Ordering::Greater => {
283	                let start = self.cursor.byte;
284	                self.cursor.byte += len;
285	                slice.subslice(start..self.cursor.byte).ok_or(DidntRead)
286	            }
287	        }
288	    }
289	
290	    fn read_u8(&mut self) -> Result<u8, DidntRead> {
291	        let slice = self.inner.slices.get(self.cursor.slice).ok_or(DidntRead)?;
292	
293	        let byte = *slice.get(self.cursor.byte).ok_or(DidntRead)?;
294	        self.cursor.byte += 1;
295	        if self.cursor.byte == slice.len() {
296	            self.cursor.slice += 1;
297	            self.cursor.byte = 0;
298	        }
299	        Ok(byte)
300	    }
301	
302	    fn can_read(&self) -> bool {
303	        self.inner.slices.get(self.cursor.slice).is_some()
304	    }
305	}
