320	impl SiphonableReader for ZBufReader<'_> {
321	    fn siphon<W>(&mut self, writer: &mut W) -> Result<NonZeroUsize, DidntSiphon>
322	    where
323	        W: Writer,
324	    {
325	        let mut read = 0;
326	        while let Some(slice) = self.inner.slices.get(self.cursor.slice) {
327	            // Subslice from the current read slice
328	            // SAFETY: self.cursor.byte is ensured by the reader.
329	            let from = crate::unsafe_slice!(slice.as_slice(), self.cursor.byte..);
330	            // Copy the slice content
331	            match writer.write(from) {
332	                Ok(len) => {
333	                    // Update the counter
334	                    read += len.get();
335	                    // Move the byte cursor
336	                    self.cursor.byte += len.get();
337	                    // We consumed all the current read slice, move to the next slice
338	                    if self.cursor.byte == slice.len() {
339	                        self.cursor.slice += 1;
340	                        self.cursor.byte = 0;
341	                    }
342	                }
343	                Err(_) => {
344	                    return NonZeroUsize::new(read).ok_or(DidntSiphon);
345	                }
346	            }
347	        }
348	        NonZeroUsize::new(read).ok_or(DidntSiphon)
349	    }
350	}
