362	impl AdvanceableReader for ZBufReader<'_> {
363	    fn skip(&mut self, offset: usize) -> Result<(), DidntRead> {
364	        let mut remaining_offset = offset;
365	        while remaining_offset > 0 {
366	            let s = self.inner.slices.get(self.cursor.slice).ok_or(DidntRead)?;
367	            let remains_in_current_slice = s.len() - self.cursor.byte;
368	            let advance = remaining_offset.min(remains_in_current_slice);
369	            remaining_offset -= advance;
370	            self.cursor.byte += advance;
371	            if self.cursor.byte == s.len() {
372	                self.cursor.slice += 1;
373	                self.cursor.byte = 0;
374	            }
375	        }
376	        Ok(())
377	    }
378	
379	    fn backtrack(&mut self, offset: usize) -> Result<(), DidntRead> {
380	        let mut remaining_offset = offset;
381	        while remaining_offset > 0 {
382	            let backtrack = remaining_offset.min(self.cursor.byte);
383	            remaining_offset -= backtrack;
384	            self.cursor.byte -= backtrack;
385	            if self.cursor.byte == 0 {
386	                if self.cursor.slice == 0 {
387	                    break;
388	                }
389	                self.cursor.slice -= 1;
390	                self.cursor.byte = self
391	                    .inner
392	                    .slices
393	                    .get(self.cursor.slice)
394	                    .ok_or(DidntRead)?
395	                    .len();
396	            }
397	        }
398	        if remaining_offset == 0 {
399	            Ok(())
400	        } else {
401	            Err(DidntRead)
402	        }
403	    }
404	}
405	
406	#[cfg(feature = "std")]
407	impl io::Seek for ZBufReader<'_> {
408	    fn seek(&mut self, pos: io::SeekFrom) -> io::Result<u64> {
409	        let current_pos = self
410	            .inner
411	            .slices()
412	            .take(self.cursor.slice)
413	            .fold(0, |acc, s| acc + s.len())
414	            + self.cursor.byte;
415	        let current_pos =
416	            i64::try_from(current_pos).map_err(|e| std::io::Error::other(e.to_string()))?;
417	
418	        let offset = match pos {
419	            std::io::SeekFrom::Start(s) => i64::try_from(s).unwrap_or(i64::MAX) - current_pos,
420	            std::io::SeekFrom::Current(s) => s,
421	            std::io::SeekFrom::End(s) => self.inner.len() as i64 + s - current_pos,
422	        };
423	        match self.advance(offset as isize) {
424	            Ok(()) => Ok((offset + current_pos) as u64),
425	            Err(_) => Err(std::io::Error::new(
426	                std::io::ErrorKind::InvalidInput,
427	                "InvalidInput",
428	            )),
429	        }
430	    }
431	}
