433	// ZSlice iterator
434	#[derive(Debug)]
435	pub struct ZBufSliceIterator<'a, 'b> {
436	    reader: &'a mut ZBufReader<'b>,
437	    remaining: usize,
438	}
439	
440	impl Iterator for ZBufSliceIterator<'_, '_> {
441	    type Item = ZSlice;
442	
443	    fn next(&mut self) -> Option<Self::Item> {
444	        if self.remaining == 0 {
445	            return None;
446	        }
447	
448	        // SAFETY: self.reader.cursor.slice is ensured by the reader.
449	        let slice =
450	            crate::unsafe_slice!(self.reader.inner.slices.as_ref(), self.reader.cursor.slice);
451	        let start = self.reader.cursor.byte;
452	        // SAFETY: self.reader.cursor.byte is ensured by the reader.
453	        let current = crate::unsafe_slice!(slice, start..);
454	        let len = current.len();
455	        match self.remaining.cmp(&len) {
456	            cmp::Ordering::Less => {
457	                let end = start + self.remaining;
458	                let slice = slice.subslice(start..end);
459	                self.reader.cursor.byte = end;
460	                self.remaining = 0;
461	                slice
462	            }
463	            cmp::Ordering::Equal => {
464	                let end = start + self.remaining;
465	                let slice = slice.subslice(start..end);
466	                self.reader.cursor.slice += 1;
467	                self.reader.cursor.byte = 0;
468	                self.remaining = 0;
469	                slice
470	            }
471	            cmp::Ordering::Greater => {
472	                let end = start + len;
473	                let slice = slice.subslice(start..end);
474	                self.reader.cursor.slice += 1;
475	                self.reader.cursor.byte = 0;
476	                self.remaining -= len;
477	                slice
478	            }
479	        }
480	    }
481	
482	    fn size_hint(&self) -> (usize, Option<usize>) {
483	        (1, None)
484	    }
485	}
