487	// Writer
488	#[derive(Debug)]
489	pub struct ZBufWriter<'a> {
490	    inner: NonNull<ZBuf>,
491	    zslice_writer: Option<ZSliceWriter<'a>>,
492	}
493	
494	impl<'a> ZBufWriter<'a> {
495	    #[inline]
496	    fn zslice_writer(&mut self) -> &mut ZSliceWriter<'a> {
497	        if self.zslice_writer.is_none() {
498	            // SAFETY: `self.inner` is valid as guaranteed by `self.writer` borrow.
499	            let zbuf = unsafe { self.inner.as_mut() };
500	            zbuf.slices.push(ZSlice::empty());
501	            self.zslice_writer = zbuf.slices.last_mut().unwrap().writer();
502	        }
503	        self.zslice_writer.as_mut().unwrap()
504	    }
505	}
506	
507	impl<'a> HasWriter for &'a mut ZBuf {
508	    type Writer = ZBufWriter<'a>;
509	
510	    fn writer(self) -> Self::Writer {
511	        ZBufWriter {
512	            inner: NonNull::new(self).unwrap(),
513	            zslice_writer: self.opt_zslice_writer(),
514	        }
515	    }
516	}
517	
518	impl Writer for ZBufWriter<'_> {
519	    fn write(&mut self, bytes: &[u8]) -> Result<NonZeroUsize, DidntWrite> {
520	        self.zslice_writer().write(bytes)
521	    }
522	
523	    fn write_exact(&mut self, bytes: &[u8]) -> Result<(), DidntWrite> {
524	        self.zslice_writer().write_exact(bytes)
525	    }
526	
527	    fn remaining(&self) -> usize {
528	        usize::MAX
529	    }
530	
531	    fn write_zslice(&mut self, slice: &ZSlice) -> Result<(), DidntWrite> {
532	        self.zslice_writer = None;
533	        // SAFETY: `self.inner` is valid as guaranteed by `self.writer` borrow,
534	        // and `self.writer` has been overwritten.
535	        unsafe { self.inner.as_mut() }.push_zslice(slice.clone());
536	        Ok(())
537	    }
538	
539	    /// # Safety
540	    ///
541	    /// The `write` closure must return the number of bytes actually written to the slice,
542	    /// which must be less than or equal to `len`.
543	    unsafe fn with_slot<F>(&mut self, len: usize, write: F) -> Result<NonZeroUsize, DidntWrite>
544	    where
545	        F: FnOnce(&mut [u8]) -> usize,
546	    {
547	        // SAFETY: Same precondition as this function. Call to `with_slot` is safe because
548	        // the requirements are passed through.
549	        unsafe { self.zslice_writer().with_slot(len, write) }
550	    }
551	}
552	
553	impl BacktrackableWriter for ZBufWriter<'_> {
554	    type Mark = ZBufPos;
555	
556	    fn mark(&mut self) -> Self::Mark {
557	        let byte = self.zslice_writer.as_mut().map(|w| w.mark());
558	        // SAFETY: `self.inner` is valid as guaranteed by `self.writer` borrow.
559	        let zbuf = unsafe { self.inner.as_mut() };
560	        ZBufPos {
561	            slice: zbuf.slices.len(),
562	            byte: byte
563	                .or_else(|| Some(zbuf.opt_zslice_writer()?.mark()))
564	                .unwrap_or(0),
565	        }
566	    }
567	
568	    fn rewind(&mut self, mark: Self::Mark) -> bool {
569	        // SAFETY: `self.inner` is valid as guaranteed by `self.writer` borrow,
570	        // and `self.writer` is reassigned after modification.
571	        let zbuf = unsafe { self.inner.as_mut() };
572	        zbuf.slices.truncate(mark.slice);
573	        self.zslice_writer = zbuf.opt_zslice_writer();
574	        if let Some(writer) = &mut self.zslice_writer {
575	            writer.rewind(mark.byte);
576	        }
577	        true
578	    }
579	}
