393	    fn read_zslices<F: FnMut(ZSlice)>(&mut self, len: usize, mut f: F) -> Result<(), DidntRead> {
394	        let zslice = self.read_zslice(len)?;
395	        f(zslice);
396	        Ok(())
397	    }
