399	    #[inline(always)]
400	    fn read_zslice(&mut self, len: usize) -> Result<ZSlice, DidntRead> {
401	        let res = self.subslice(..len).ok_or(DidntRead)?;
402	        self.start += len;
403	        Ok(res)
