162	    fn _wrap_in_place<const ID: u8>(
163	        shm_provider: &ShmProvider<PosixShmProviderBackend>,
164	        ext_shm: &mut Option<ShmType<ID>>,
165	        slice: &mut ZSlice,
166	    ) {
167	        if let Ok(mut shmbuf) = unsafe {
