210	pub fn map_zmsg_to_partner<ShmCfg: PartnerShmConfig>(
211	    msg: &mut NetworkMessageMut,
212	    partner_shm_cfg: &ShmCfg,
213	    shm_provider: &Option<Arc<LazyShmProvider>>,
214	) {
215	    match &mut msg.body {
216	        NetworkBodyMut::Push(Push { payload, .. }) => match payload {
217	            PushBody::Put(b) => b.map_to_partner(partner_shm_cfg, shm_provider),
218	            PushBody::Del(_) => {}
219	        },
220	        NetworkBodyMut::Request(Request { payload, .. }) => match payload {
221	            RequestBody::Query(b) => b.map_to_partner(partner_shm_cfg, shm_provider),
222	        },
223	        NetworkBodyMut::Response(Response { payload, .. }) => match payload {
224	            ResponseBody::Reply(b) => b.map_to_partner(partner_shm_cfg, shm_provider),
225	            ResponseBody::Err(b) => b.map_to_partner(partner_shm_cfg, shm_provider),
226	        },
227	        NetworkBodyMut::ResponseFinal(_)
228	        | NetworkBodyMut::Interest(_)
229	        | NetworkBodyMut::Declare(_)
230	        | NetworkBodyMut::OAM(_) => {}
231	    }
232	}
