235	    match msg.body {
236	        NetworkBodyMut::Push(Push { payload, .. }) => match payload {
237	            PushBody::Put(b) => b.map_to_shmbuf(shmr),
238	            PushBody::Del(_) => Ok(()),
239	        },
240	        NetworkBodyMut::Request(Request { payload, .. }) => match payload {
241	            RequestBody::Query(b) => b.map_to_shmbuf(shmr),
242	        },
243	        NetworkBodyMut::Response(Response { payload, .. }) => match payload {
244	            ResponseBody::Err(b) => b.map_to_shmbuf(shmr),
245	            ResponseBody::Reply(b) => b.map_to_shmbuf(shmr),
246	        },
247	        NetworkBodyMut::ResponseFinal(_)
248	        | NetworkBodyMut::Interest(_)
249	        | NetworkBodyMut::Declare(_)
250	        | NetworkBodyMut::OAM(_) => Ok(()),
251	    }
252	}
